// runOnceForAllItems: receives all exec responses, pairs with agent info
const execItems = $input.all();
const agentItems = $('Get Active Agents').all();

const reports = [];
for (let i = 0; i < execItems.length; i++) {
  const agentInfo = agentItems[i] ? agentItems[i].json : { agent_name: 'unknown', workflow_id: 'unknown' };
  const agentName = agentInfo.agent_name;
  const workflowId = agentInfo.workflow_id;
  const execData = execItems[i].json;

  if (execData.error || execData.code) {
    reports.push({ agent_name: agentName, workflow_id: workflowId, status: 'api_error', consecutive_errors: 0, issue: false });
    continue;
  }
  const executions = execData.data || [];
  if (executions.length === 0) {
    reports.push({ agent_name: agentName, workflow_id: workflowId, status: 'no_executions', consecutive_errors: 0, issue: false });
    continue;
  }
  let consecutiveErrors = 0;
  for (const exec of executions) {
    if (exec.status === 'error') { consecutiveErrors++; } else { break; }
  }
  const lastExec = executions[0];
  reports.push({
    agent_name: agentName, workflow_id: workflowId,
    consecutive_errors: consecutiveErrors,
    should_retire: consecutiveErrors >= 3,
    last_status: lastExec.status,
    last_run_at: lastExec.startedAt,
    issue: consecutiveErrors >= 1
  });
}

const issues = reports.filter(r => r.issue);
const retiring = reports.filter(r => r.should_retire);

return [{ json: {
  scan_time: new Date().toISOString(),
  total_agents_checked: reports.length,
  agents_with_issues: issues.length,
  agents_retiring: retiring.length,
  issues: issues,
  retiring: retiring,
  all_reports: reports
}}];

// Read directly from Analyze All Agents — Write Audit Log returns empty body (Prefer:return=minimal)
const report = $('Analyze All Agents').first().json;
if (!report || report.agents_with_issues === 0) return [];
return [{ json: report }];

// Read directly from Analyze All Agents — fan out one item per retiring agent
const report = $('Analyze All Agents').first().json;
const retiring = report.retiring || [];
if (retiring.length === 0) return [];
// Return one item per retiring agent so downstream nodes process each individually
return retiring.map(r => ({ json: { ...r, scan_time: report.scan_time } }));

